{"type":"item.started","item":{"id":"item_15","type":"command_execution","command":"/bin/bash -lc "cat > /root/output/js/visualization.js << 'JSEOF'
(function () {
  const BUBBLE_SVG_W = 800;
  const BUBBLE_SVG_H = 700;
  const MARGIN = { top: 20, right: 20, bottom: 20, left: 20 };

  // Sector color palette
  const SECTOR_COLORS = {
    \"Information Technology\": \"#4e79a7\",
    \"Industry\": \"#f28e2b\",
    \"Energy\": \"#e15759\",
    \"Financial\": \"#76b7b2\",
    \"ETF\": \"#b07aa1\"
  };

  // Sector anchor positions (normalized 0-1, will be scaled to SVG dims)
  const SECTOR_ANCHORS = {
    \"Information Technology\": { x: 0.25, y: 0.28 },
    \"Industry\":               { x: 0.72, y: 0.25 },
    \"Energy\":                 { x: 0.72, y: 0.72 },
    \"Financial\":              { x: 0.25, y: 0.72 },
    \"ETF\":                    { x: 0.50, y: 0.50 }
  };

  function formatMarketCap(val) {
    if ("'!val || isNaN(val)) return "N/A";
    const n = +val;
    if (n >= 1e12) return (n / 1e12).toFixed(2) + "T";
    if (n >= 1e9)  return (n / 1e9).toFixed(2) + "B";
    if (n >= 1e6)  return (n / 1e6).toFixed(2) + "M";
    return n.toFixed(0);
  }

  function init() {
    d3.csv("data/stock-descriptions.csv").then(function (raw) {
      // Parse fields
      const data = raw.map(function (d) {
        return {
          ticker:      d.ticker,
          sector:      d.sector,
          name:        d["full name"],
          marketCap:   d.marketCap ? +d.marketCap : null,
          country:     d.country || null,
          website:     d.website || null,
          isETF:       d.sector === "ETF"
        };
      });

      buildBubbleChart(data);
      buildTable(data);
    });
  }

  function buildBubbleChart(data) {
    const w = BUBBLE_SVG_W;
    const h = BUBBLE_SVG_H;

    // Radius scale based on market cap
    const caps = data.filter(d => d.marketCap).map(d => d.marketCap);
    const rScale = d3.scaleSqrt()
      .domain([0, d3.max(caps)])
      .range([6, 52]);

    const ETF_RADIUS = 18;

    data.forEach(function (d) {
      d.radius = d.isETF ? ETF_RADIUS : (d.marketCap ? rScale(d.marketCap) : 10);
    });

    const svg = d3.select("#bubble-chart")
      .append("svg")
      .attr("width", w)
      .attr("height", h);

    // Defs for clip paths per bubble
    const defs = svg.append("defs");

    // Tooltip
    const tooltip = d3.select("#tooltip");

    // Sector anchor pixel coords
    const anchors = {};
    Object.keys(SECTOR_ANCHORS).forEach(function (s) {
      anchors[s] = {
        x: SECTOR_ANCHORS[s].x * w,
        y: SECTOR_ANCHORS[s].y * h
      };
    });

    // Initialize positions near sector anchor
    data.forEach(function (d) {
      const a = anchors[d.sector];
      d.x = a.x + (Math.random() - 0.5) * 60;
      d.y = a.y + (Math.random() - 0.5) * 60;
    });

    // Force simulation with sector clustering
    const simulation = d3.forceSimulation(data)
      .force("x", d3.forceX(d => anchors[d.sector].x).strength(0.25))
      .force("y", d3.forceY(d => anchors[d.sector].y).strength(0.25))
      .force("collide", d3.forceCollide(d => d.radius + 2).strength(0.85).iterations(3))
      .force("center", d3.forceCenter(w / 2, h / 2).strength(0.02))
      .alphaDecay(0.02)
      .stop();

    // Run simulation synchronously for stable layout
    for (let i = 0; i < 300; i++) simulation.tick();

    // Clamp positions so bubbles stay within SVG
    data.forEach(function (d) {
      d.x = Math.max(d.radius + 2, Math.min(w - d.radius - 2, d.x));
      d.y = Math.max(d.radius + 2, Math.min(h - d.radius - 2, d.y));
    });

    // Draw bubbles
    const node = svg.selectAll("g.bubble")
      .data(data)
      .enter()
      .append("g")
      .attr("class", "bubble")
      .attr("data-ticker", d => d.ticker)
      .attr("transform", d => `translate(${d.x},${d.y})`);

    node.append("circle")
      .attr("r", d => d.radius)
      .attr("fill", d => SECTOR_COLORS[d.sector] || "#aaa")
      .attr("stroke", "#fff")
      .attr("stroke-width", 1.5)
      .style("cursor", "pointer");

    node.append("text")
      .attr("text-anchor", "middle")
      .attr("dy", "0.35em")
      .attr("font-size", d => Math.min(d.radius * 0.55, 13) + "px")
      .attr("fill", "#fff")
      .attr("pointer-events", "none")
      .text(d => d.ticker);

    // Hover tooltip (skip ETFs)
    node.on("mouseover", function (event, d) {
        if (d.isETF) return;
        tooltip
          .style("display", "block")
          .html(
            `<strong>${d.ticker}</strong><br/>` +
            `${d.name}<br/>` +
            `<em>${d.sector}</em>`
          );
      })
      .on("mousemove", function (event) {
        tooltip
          .style("left", (event.pageX + 12) + "px")
          .style("top",  (event.pageY - 28) + "px");
      })
      .on("mouseout", function () {
        tooltip.style("display", "none");
      });

    // Click: highlight bubble + table row
    node.on("click", function (event, d) {
      const alreadySelected = d3.select(this).classed("selected");

      // Clear all selections
      svg.selectAll("g.bubble").classed("selected", false);
      svg.selectAll("g.bubble circle").attr("stroke", "#fff").attr("stroke-width", 1.5);
      d3.selectAll("#stock-table tbody tr").classed("highlighted", false);

      if (!alreadySelected) {
        d3.select(this).classed("selected", true);
        d3.select(this).select("circle").attr("stroke", "#222").attr("stroke-width", 3);

        // Highlight table row
        const row = d3.select(`#stock-table tbody tr[data-ticker="${d.ticker}"]`);
        row.classed("highlighted", true);
        // Scroll row into view
        const rowNode = row.node();
        if (rowNode) rowNode.scrollIntoView({ block: "nearest", behavior: "smooth" });
      }
    });

    // Legend
    buildLegend(svg, w, h);
  }

  function buildLegend(svg, w, h) {
    const sectors = Object.keys(SECTOR_COLORS);
    const legendG = svg.append("g")
      .attr("class", "legend")
      .attr("transform", `translate(10, ${h - sectors.length * 22 - 10})`);

    sectors.forEach(function (s, i) {
      const row = legendG.append("g").attr("transform", `translate(0, ${i * 22})`);
      row.append("rect")
        .attr("width", 14).attr("height", 14)
        .attr("rx", 3)
        .attr("fill", SECTOR_COLORS[s]);
      row.append("text")
        .attr("x", 20).attr("y", 11)
        .attr("font-size", "12px")
        .attr("fill", "#333")
        .text(s);
    });
  }

