(function () {
  const WIDTH = 700;
  const HEIGHT = 620;
  const LEGEND_HEIGHT = 60;

  // Sector color palette
  const SECTOR_COLORS = {
    \"Information Technology\": \"#4e79a7\",
    \"Industry\": \"#f28e2b\",
    \"Energy\": \"#e15759\",
    \"Financial\": \"#76b7b2\",
    \"ETF\": \"#b07aa1\"
  };

  // Sector cluster anchor positions (normalized 0-1, will be scaled)
  const SECTOR_ANCHORS = {
    \"Information Technology\": { x: 0.25, y: 0.35 },
    \"Industry\":               { x: 0.72, y: 0.28 },
    \"Energy\":                 { x: 0.72, y: 0.72 },
    \"Financial\":              { x: 0.25, y: 0.72 },
    \"ETF\":                    { x: 0.50, y: 0.50 }
  };

  const ETF_RADIUS = 18;

  function formatMarketCap(val) {
    if ("'!val || isNaN(+val)) return "N/A";
    const n = +val;
    if (n >= 1e12) return (n / 1e12).toFixed(2) + "T";
    if (n >= 1e9)  return (n / 1e9).toFixed(2) + "B";
    if (n >= 1e6)  return (n / 1e6).toFixed(2) + "M";
    return n.toFixed(0);
  }

  d3.csv("data/stock-descriptions.csv").then(function (rawData) {
    // Parse data — filter out malformed rows (no ticker)
    const data = rawData.filter(d => d.ticker && d.ticker.trim() !== "");

    // Compute radius scale from market cap
    const caps = data.filter(d => d.marketCap && !isNaN(+d.marketCap)).map(d => +d.marketCap);
    const capExtent = d3.extent(caps);
    const radiusScale = d3.scaleSqrt().domain(capExtent).range([14, 52]);

    data.forEach(d => {
      d.isETF = d.sector === "ETF";
      d.radius = d.isETF ? ETF_RADIUS : (d.marketCap && !isNaN(+d.marketCap) ? radiusScale(+d.marketCap) : 14);
    });

    // ---- SVG setup ----
    const svg = d3.select("#bubble-chart")
      .attr("width", WIDTH)
      .attr("height", HEIGHT);

    // ---- Tooltip ----
    const tooltip = d3.select("#tooltip");

    // ---- Table ----
    buildTable(data);

    // ---- Bubble nodes ----
    const node = svg.selectAll(".bubble")
      .data(data)
      .join("g")
      .attr("class", "bubble")
      .attr("data-ticker", d => d.ticker);

    node.append("circle")
      .attr("r", d => d.radius)
      .attr("fill", d => SECTOR_COLORS[d.sector] || "#999")
      .on("mouseover", function (event, d) {
        if (d.isETF) return;
        tooltip
          .classed("visible", true)
          .html(
            `<div class="tt-ticker">${d.ticker}</div>` +
            `<div class="tt-name">${d["full name"]}</div>` +
            `<div class="tt-sector">${d.sector}</div>`
          );
      })
      .on("mousemove", function (event) {
        tooltip
          .style("left", (event.pageX + 14) + "px")
          .style("top",  (event.pageY - 28) + "px");
      })
      .on("mouseout", function (event, d) {
        if (d.isETF) return;
        tooltip.classed("visible", false);
      })
      .on("click", function (event, d) {
        selectTicker(d.ticker);
      });

    node.append("text")
      .text(d => d.ticker)
      .style("font-size", d => Math.min(11, d.radius * 0.55) + "px");

    // ---- Legend ----
    const legendContainer = d3.select("#legend");
    Object.entries(SECTOR_COLORS).forEach(([sector, color]) => {
      const item = legendContainer.append("div")
        .attr("class", "legend-item")
        .attr("data-sector", sector);
      item.append("div")
        .attr("class", "legend-swatch")
        .style("background", color);
      item.append("span").text(sector);
    });

    // ---- Force simulation ----
    const simulation = d3.forceSimulation(data)
      .force("x", d3.forceX(d => SECTOR_ANCHORS[d.sector].x * WIDTH).strength(0.12))
      .force("y", d3.forceY(d => SECTOR_ANCHORS[d.sector].y * HEIGHT).strength(0.12))
      .force("collide", d3.forceCollide(d => d.radius + 2).strength(0.85))
      .force("charge", d3.forceManyBody().strength(-8))
      .on("tick", () => {
        node.attr("transform", d => `translate(${d.x},${d.y})`);
      });

    // Run simulation to near-completion
    simulation.alpha(1).restart();

    // ---- Selection logic ----
    function selectTicker(ticker) {
      // Deselect all
      svg.selectAll(".bubble circle").classed("selected", false);
      d3.selectAll("#stock-table tbody tr").classed("selected", false);

      // Select bubble
      svg.selectAll(`.bubble[data-ticker="${ticker}"] circle`).classed("selected", true);

      // Select + scroll table row
      const row = d3.select(`#stock-table tbody tr[data-ticker="${ticker}"]`);
      row.classed("selected", true);
      const rowNode = row.node();
      if (rowNode) rowNode.scrollIntoView({ block: "nearest", behavior: "smooth" });
    }

    window._selectTicker = selectTicker;
  });

  function buildTable(data) {
    const tbody = d3.select("#stock-table tbody");

    const rows = tbody.selectAll("tr")
      .data(data)
      .join("tr")
      .attr("data-ticker", d => d.ticker)
      .on("click", function (event, d) {
        window._selectTicker && window._selectTicker(d.ticker);
      });

    rows.append("td").text(d => d.ticker);
    rows.append("td").text(d => d["full name"]);
    rows.append("td").text(d => d.sector);
    rows.append("td").text(d => formatMarketCap(d.marketCap));
  }
})();
